import { Component, OnInit, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient, HttpParams } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-hr-dashboard',
  // Inline Template (HTML)
  template: `
  <div class="dashboard-wrapper">
    <header class="header-nav">
      <div class="nav-brand">
        <h1>InternConnect <span class="hr-pill">HR PORTAL</span></h1>
      </div>
      <div class="nav-actions">
        <span class="admin-name">{{auth.user?.name || 'Administrator'}}</span>
        <button class="btn-outline btn-danger" (click)="logout()">Logout</button>
      </div>
    </header>

    <main class="dashboard-grid">
      <aside class="sidebar-panel">
        <div class="pro-card">
          <h2 class="card-title">Post New Internship</h2>
          <div class="form-grid">
            <input class="modern-input" placeholder="Role Title" [(ngModel)]="title" />
            <input class="modern-input" placeholder="Location" [(ngModel)]="location" />
            <input class="modern-input" placeholder="CTC" [(ngModel)]="ctc" />
            <input class="modern-input" placeholder="Company" [(ngModel)]="companyName" />
            <textarea class="modern-input" placeholder="Job Description" rows="3" [(ngModel)]="description"></textarea>

            <div class="upload-section">
              <label class="file-label">Job Description PDF</label>
              <input type="file" (change)="onPdfSelected($event)" class="modern-input" />
              <div class="btn-group">
                <button (click)="handlePdfUpload()" class="btn-outline">Upload PDF</button>
                <button *ngIf="pdfUploaded" (click)="handlePost()" class="btn-pro">Post Internship</button>
              </div>
            </div>
          </div>
        </div>

        <h3 class="card-title" style="margin-top: 2rem;">Current Openings</h3>
        <div class="pro-card list-scroll">
          <div *ngFor="let i of internships" class="list-item">
            <div class="item-info">
              <h4>{{i.title}}</h4>
              <p>{{i.companyName}} • {{i.location}}</p>
            </div>
            <button class="btn-icon-delete" (click)="handleDelete(i.id)">
               <svg width="16" height="16" fill="currentColor" viewBox="0 0 16 16"><path d="M5.5 5.5A.5.5 0 0 1 6 6v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm2.5 0a.5.5 0 0 1 .5.5v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm3 .5a.5.5 0 0 0-1 0v6a.5.5 0 0 0 1 0V6z"/><path fill-rule="evenodd" d="M14.5 3a1 1 0 0 1-1 1H13v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V4h-.5a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1H6a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1h3.5a1 1 0 0 1 1 1v1zM4.118 4 4 4.059V13a1 1 0 0 0 1 1h6a1 1 0 0 0 1-1V4.059L11.882 4H4.118zM2.5 3V2h11v1h-11z"/></svg>
            </button>
          </div>
        </div>
      </aside>

      <section class="main-content">
        <h2 class="card-title">Candidate Management Pipeline</h2>

        <div *ngFor="let app of applications" class="pro-card candidate-row">
          <div class="row-header">
            <div>
              <span class="candidate-name">{{app.candidateName}}</span>
              <span class="badge badge-process">{{app.status?.replace('_', ' ')}}</span>
              <p class="text-muted">{{app.email}} | {{app.phone}}</p>
            </div>
            <button class="btn-outline" (click)="selectedCandidate = app">View Full Profile</button>
          </div>

          <div class="pipeline-steps">
            <div class="step">
              <span class="step-label">Online Test</span>
              <span class="text-success">✓ Passed</span>
            </div>

            <div class="step" *ngIf="app.l1Date">
              <span class="step-label">L1 Interview</span>
              <p>{{formatDate(app.l1Date)}} | {{getInterviewerName(app.l1InterviewerId)}}</p>
              <span class="res-tag" [class.pass]="app.l1Result === 'PASSED'">{{app.l1Result || 'Pending'}}</span>
            </div>

            <div class="step" *ngIf="app.hrDate">
              <span class="step-label">HR Round</span>
              <p>{{formatDate(app.hrDate)}} | {{app.hrMode}}</p>
              <span class="res-tag" [class.pass]="app.hrResult === 'PASSED'">{{app.hrResult || 'Pending'}}</span>
            </div>
          </div>

          <div *ngIf="showScheduleOptions(app)" class="scheduling-action-box">
            <div class="input-row">
              <input type="date" class="modern-input" [ngModel]="getScheduleValue(app.id,'date')" (ngModelChange)="setScheduleValue(app.id,'date',$event)" />
              <input type="time" class="modern-input" [ngModel]="getScheduleValue(app.id,'time')" (ngModelChange)="setScheduleValue(app.id,'time',$event)" />
              <select class="modern-input" [ngModel]="getScheduleValue(app.id,'mode')" (ngModelChange)="setScheduleValue(app.id,'mode',$event)">
                <option value="">Mode</option>
                <option value="ONLINE">Online</option>
                <option value="OFFLINE">Offline</option>
              </select>
              <select *ngIf="app.status !== 'HR_PENDING'" class="modern-input" [ngModel]="getScheduleValue(app.id,'interviewerId')" (ngModelChange)="setScheduleValue(app.id,'interviewerId',$event)">
                <option value="">Interviewer</option>
                <option *ngFor="let iv of interviewerOptionsForApp(app)" [value]="iv.id">{{ iv.name }}</option>
              </select>
            </div>
            <button (click)="scheduleInterview(app.id, app.status)" class="btn-pro full-w">{{ scheduleLabel(app) }}</button>
          </div>

          <div *ngIf="app.interviewStatus === 'HR_SCHEDULED' && app.status !== 'SELECTED' && app.status !== 'REJECTED'" class="decision-box">
            <button (click)="updateHrResult(app.id, 'HR_PASSED')" class="btn-pro success-btn">Select for Offer</button>
            <button (click)="updateHrResult(app.id, 'HR_FAILED')" class="btn-outline danger-btn">Reject</button>
          </div>

          <div *ngIf="app.status === 'SELECTED' || app.status === 'OFFER_PENDING'" class="offer-flow">
             <div *ngIf="!app.offerLetterFile" class="upload-offer">
               <label>Generate Offer Letter (PDF)</label>
               <input type="file" (change)="handleOfferFileChange(app.id, $event)" />
               <button (click)="uploadOfferLetter(app.id)" class="btn-pro">Upload & Send</button>
             </div>

             <div *ngIf="app.signedOfferLetter" class="onboarding-ready">
                <div class="alert-success">Signed Offer Received! Ready for onboarding.</div>
                <button class="btn-pro" (click)="router.navigate(['/hr/onboarding', app.email])">Manage Onboarding</button>
                <button *ngIf="!employeeExists(app.email)" class="btn-pro dark-btn" (click)="router.navigate(['/hr/create-employee', app.email], { state: { applicationId: app.id } })">Create Employee ID</button>
             </div>
          </div>
        </div>
      </section>
    </main>

    <div *ngIf="selectedCandidate" class="overlay-panel">
      <div class="overlay-header">
        <h3>Full Application Details</h3>
        <button (click)="selectedCandidate=null" class="close-icon">&times;</button>
      </div>
      <div class="overlay-body">
        <div class="info-group"><span>Name</span><strong>{{selectedCandidate.candidateName}}</strong></div>
        <div class="info-group"><span>Education</span><strong>{{selectedCandidate.degree}} - {{selectedCandidate.college}}</strong></div>
        <div class="info-group"><span>CGPA</span><strong>{{selectedCandidate.cgpa}}</strong></div>
        <div class="info-group"><span>Skills</span><strong>{{selectedCandidate.skills}}</strong></div>
        <hr/>
        <a [href]="'http://localhost:8080/resumes/' + selectedCandidate.resumeFileName" target="_blank" class="resume-link">Download Resume (PDF)</a>
      </div>
    </div>
  </div>
  `,
  // Inline Styles (CSS)
  styles: [`
    :host {
      --primary: #4f46e5;
      --primary-dark: #3730a3;
      --bg: #f8fafc;
      --white: #ffffff;
      --text: #1e293b;
      --text-muted: #64748b;
      --border: #e2e8f0;
      --success: #10b981;
      --danger: #ef4444;
    }

    .dashboard-wrapper { background: var(--bg); min-height: 100vh; font-family: 'Inter', system-ui, sans-serif; color: var(--text); }

    .header-nav { 
      background: var(--white); padding: 0.8rem 2.5rem; display: flex; justify-content: space-between; 
      align-items: center; border-bottom: 1px solid var(--border); position: sticky; top: 0; z-index: 100;
    }
    .nav-brand h1 { font-size: 1.3rem; font-weight: 800; margin: 0; }
    .hr-pill { background: #eef2ff; color: var(--primary); padding: 4px 10px; border-radius: 6px; font-size: 0.75rem; }
    .admin-name { font-weight: 600; font-size: 0.9rem; margin-right: 1.5rem; color: var(--text-muted); }

    .dashboard-grid { display: grid; grid-template-columns: 360px 1fr; gap: 2.5rem; padding: 2.5rem; max-width: 1500px; margin: 0 auto; }

    .pro-card { background: var(--white); border: 1px solid var(--border); border-radius: 16px; padding: 1.8rem; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.05); margin-bottom: 1.5rem; }
    .card-title { font-size: 1.1rem; font-weight: 700; margin-bottom: 1.2rem; }

    .modern-input { width: 100%; padding: 0.8rem; border: 1.5px solid var(--border); border-radius: 10px; margin-bottom: 0.8rem; outline: none; transition: 0.2s; font-size: 0.9rem; box-sizing: border-box; }
    .modern-input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(79, 70, 229, 0.1); }

    .btn-pro { background: var(--primary); color: white; border: none; padding: 0.8rem 1.2rem; border-radius: 10px; font-weight: 700; cursor: pointer; transition: 0.2s; }
    .btn-pro:hover { background: var(--primary-dark); transform: translateY(-1px); }
    .btn-outline { background: white; border: 1.5px solid var(--border); padding: 0.7rem 1.2rem; border-radius: 10px; font-weight: 600; cursor: pointer; }
    .danger-btn { color: var(--danger); border-color: #fee2e2; }
    .success-btn { background: var(--success); }
    .dark-btn { background: #0f172a; }

    .list-scroll { max-height: 400px; overflow-y: auto; padding: 0.5rem; }
    .list-item { display: flex; justify-content: space-between; align-items: center; padding: 12px; border-bottom: 1px solid #f1f5f9; }
    .item-info h4 { margin: 0; font-size: 0.9rem; }
    .item-info p { margin: 4px 0 0; font-size: 0.75rem; color: var(--text-muted); }
    .btn-icon-delete { background: #fff1f2; color: var(--danger); border: none; padding: 6px; border-radius: 6px; cursor: pointer; }

    .candidate-row { transition: 0.2s; }
    .candidate-row:hover { border-color: var(--primary); }
    .row-header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 1.5rem; }
    .candidate-name { font-size: 1.2rem; font-weight: 800; margin-right: 12px; }
    .badge { padding: 4px 10px; border-radius: 6px; font-size: 0.7rem; font-weight: 700; text-transform: uppercase; }
    .badge-process { background: #f1f5f9; color: #475569; }

    .pipeline-steps { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1rem; padding-top: 1.2rem; border-top: 1px solid #f1f5f9; }
    .step { font-size: 0.8rem; }
    .step-label { display: block; font-weight: 700; color: var(--text-muted); font-size: 0.65rem; text-transform: uppercase; margin-bottom: 6px; }
    .res-tag { font-size: 0.7rem; font-weight: 700; color: #94a3b8; }
    .res-tag.pass { color: var(--success); }

    .scheduling-action-box { background: #f8fafc; padding: 1.2rem; border-radius: 12px; margin-top: 1.5rem; }
    .input-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin-bottom: 10px; }
    .full-w { width: 100%; }

    .overlay-panel { position: fixed; right: 0; top: 0; height: 100vh; width: 420px; background: white; z-index: 1000; box-shadow: -10px 0 30px rgba(0,0,0,0.1); padding: 2.5rem; animation: slideIn 0.3s ease; }
    @keyframes slideIn { from { transform: translateX(100%); } to { transform: translateX(0); } }
    .overlay-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 2rem; border-bottom: 1px solid #f1f5f9; padding-bottom: 1rem; }
    .close-icon { background: none; border: none; font-size: 2rem; cursor: pointer; color: var(--text-muted); }
    .info-group { margin-bottom: 1.2rem; }
    .info-group span { display: block; font-size: 0.75rem; color: var(--text-muted); font-weight: 600; margin-bottom: 4px; }
    .resume-link { display: block; background: #f1f5f9; text-align: center; padding: 12px; border-radius: 8px; text-decoration: none; color: var(--primary); font-weight: 700; }

    @media (max-width: 1100px) { .dashboard-grid { grid-template-columns: 1fr; } }
  `]
})
export class HrDashboardComponent implements OnInit, OnDestroy {
  // Logic Variables
  title = ''; location = ''; ctc = ''; description = ''; companyName = '';
  internships: any[] = []; applications: any[] = []; interviewerList: any[] = [];
  scheduleData: any = {}; selectedCandidate: any = null; offerFiles: any = {};
  uploadedOfferForApp: Record<string, string> = {}; pdfFile: any = null;
  uploadedFileName = ''; pdfUploaded = false; onboardingList: any[] = [];
  employeeList: any[] = []; 

  private intervalId: any;
  private pollingPaused = false;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() {
    if (!this.auth.user || this.auth.user.role !== 'HR') {
      this.router.navigate(['/']);
      return;
    }
    this.fetchAll();
    this.startPolling();
  }

  ngOnDestroy() { this.stopPolling(); }

  startPolling() {
    this.stopPolling();
    this.intervalId = setInterval(() => { if (!this.pollingPaused) this.fetchAll(); }, 8000);
  }

  stopPolling() { if (this.intervalId) { clearInterval(this.intervalId); this.intervalId = null; } }
  pausePolling() { this.pollingPaused = true; }
  resumePolling() { this.pollingPaused = false; }
  logout() { this.auth.logout(); this.router.navigate(['/']); }

  private fetchAll() {
    this.fetchInternships();
    this.fetchApplications();
    this.fetchOnboarding();
    this.fetchEmployees();
  }

  // --- Core API Logic ---
  async fetchOnboarding() { try { const res: any = await this.http.get('http://localhost:8080/api/onboarding').toPromise(); this.onboardingList = res || []; } catch (err) {} }
  async fetchInternships() { try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) {} }
  async fetchApplications() { try { this.applications = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise(); } catch (err) {} }
  async fetchEmployees() { try { this.employeeList = await this.http.get<any[]>('http://localhost:8080/api/employees').toPromise(); } catch (err) {} }

  formatDate(d: any) { return d ? new Date(d).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }) : ''; }

  getInterviewerName(id: number) {
    const known: Record<number, string> = { 1: 'Kavya', 2: 'Arun', 3: 'Divya' };
    if (known[id]) return known[id];
    const emp = this.employeeList?.find(e => (e.id ?? e.interviewerId ?? e.employeeId) === id);
    return emp ? (emp.name || emp.fullName || emp.email) : 'TBD';
  }

  onPdfSelected(e: any) { this.pdfFile = e.target.files?.[0]; }

  async handlePdfUpload() {
    if (!this.pdfFile) return alert('Select PDF');
    const form = new FormData(); form.append('file', this.pdfFile);
    const res = await this.http.post('http://localhost:8080/api/internships/upload-pdf', form, { responseType: 'text' }).toPromise();
    this.uploadedFileName = res as string; this.pdfUploaded = true;
    alert('PDF Processed');
  }

  async handlePost() {
    const form = new FormData();
    form.append('companyName', this.companyName); form.append('title', this.title);
    form.append('location', this.location); form.append('ctc', this.ctc);
    form.append('description', this.description); form.append('pdfFileName', this.uploadedFileName);
    await this.http.post('http://localhost:8080/api/internships/post', form).toPromise();
    this.companyName = this.title = this.location = this.ctc = this.description = '';
    this.pdfUploaded = false; this.fetchInternships();
  }

  async handleDelete(id: any) { await this.http.delete(`http://localhost:8080/api/internships/${id}`).toPromise(); this.fetchInternships(); }

  setScheduleValue(appId: any, field: string, value: any) {
    this.scheduleData = { ...this.scheduleData, [appId]: { ...(this.scheduleData[appId] || {}), [field]: value } };
  }
  getScheduleValue(appId: any, field: string) { return (this.scheduleData[appId]?.[field]) || ''; }

  async scheduleInterview(appId: any, status: any) {
    const data = this.scheduleData[appId];
    if (!data?.date || !data?.time || !data?.mode) return alert('Fill all scheduling fields');
    const params = new HttpParams()
      .set('applicationId', appId)
      .set('level', status === 'TEST_PASSED' ? 'L1' : status === 'L2_PENDING' ? 'L2' : 'HR')
      .set('date', data.date).set('time', data.time).set('mode', data.mode)
      .set('interviewerId', data.interviewerId || '');
    await this.http.post('http://localhost:8080/api/applications/schedule-interview', null, { params, responseType: 'text' }).toPromise();
    this.fetchAll();
  }

  async updateHrResult(id: any, result: string) {
    await this.http.post('http://localhost:8080/api/applications/hr-result', null, { params: new HttpParams().set('applicationId', id).set('result', result), responseType: 'text' }).toPromise();
    this.fetchAll();
  }

  handleOfferFileChange(id: any, event: any) {
    const file = event.target.files?.[0];
    if (file) this.offerFiles = { ...this.offerFiles, [id]: file };
  }

  async uploadOfferLetter(id: any) {
    const file = this.offerFiles[id];
    if (!file) return alert('Select offer file');
    const form = new FormData(); form.append('applicationId', id); form.append('file', file);
    await this.http.post('http://localhost:8080/api/applications/upload-offer-letter', form, { responseType: 'text' as 'json' }).toPromise();
    alert('Offer Dispatched'); this.fetchAll();
  }

  employeeExists(email: string) { return !!this.employeeList.find(emp => emp.email === email); }
  showScheduleOptions(app: any) { return (app.status === 'TEST_PASSED' && app.interviewStatus !== 'L1_SCHEDULED') || (app.status === 'L2_PENDING' && app.interviewStatus !== 'L2_SCHEDULED') || (app.status === 'HR_PENDING' && app.interviewStatus !== 'HR_SCHEDULED') || app.l1InterviewerStatus === 'REJECTED' || app.l2InterviewerStatus === 'REJECTED'; }
  scheduleLabel(app: any) { return app.status === 'TEST_PASSED' ? 'Schedule L1' : app.status === 'L2_PENDING' ? 'Schedule L2' : 'Schedule HR'; }
  interviewerOptionsForApp(app: any) { return [{ id: 1, name: 'Kavya' }, { id: 2, name: 'Arun' }, { id: 3, name: 'Divya' }].filter(iv => iv.id !== app.l1InterviewerId); }
}
